    private let newPasswordTextField = UITextField()
    private let confirmPasswordTextField = UITextField()
    private let resetButton = UIButton(type: .system)
    private let activityIndicator = UIActivityIndicatorView(style: .medium)
    
    init(token: String) {
        self.token = token
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground
        title = "Reset Password"
        
        setupUI()
    }
    
    private func setupUI() {
        let stackView = UIStackView()
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        let titleLabel = UILabel()
        titleLabel.text = "Reset Your Password"
        titleLabel.font = UIFont.systemFont(ofSize: 28, weight: .bold)
        titleLabel.textAlignment = .center
        
        tokenLabel.text = "Token: \(token.prefix(10))..."
        tokenLabel.font = UIFont.systemFont(ofSize: 12, weight: .regular)
        tokenLabel.textColor = .secondaryLabel
        tokenLabel.textAlignment = .center
        
        newPasswordTextField.placeholder = "New Password"
        newPasswordTextField.isSecureTextEntry = true
        newPasswordTextField.borderStyle = .roundedRect
        newPasswordTextField.autocapitalizationType = .none
        newPasswordTextField.autocorrectionType = .no
        
        confirmPasswordTextField.placeholder = "Confirm Password"
        confirmPasswordTextField.isSecureTextEntry = true
        confirmPasswordTextField.borderStyle = .roundedRect
        confirmPasswordTextField.autocapitalizationType = .none
        confirmPasswordTextField.autocorrectionType = .no
        
        resetButton.setTitle("Reset Password", for: .normal)
        resetButton.titleLabel?.font = UIFont.systemFont(ofSize: 18, weight: .semibold)
        resetButton.backgroundColor = .systemBlue
        resetButton.setTitleColor(.white, for: .normal)
        resetButton.layer.cornerRadius = 10
        resetButton.heightAnchor.constraint(equalToConstant: 50).isActive = true
        resetButton.addTarget(self, action: #selector(resetPasswordTapped), for: .touchUpInside)
        
        activityIndicator.hidesWhenStopped = true
        
        stackView.addArrangedSubview(titleLabel)
        stackView.addArrangedSubview(tokenLabel)
        stackView.addArrangedSubview(UIView())
        stackView.addArrangedSubview(newPasswordTextField)
        stackView.addArrangedSubview(confirmPasswordTextField)
        stackView.addArrangedSubview(resetButton)
        stackView.addArrangedSubview(activityIndicator)
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 40),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -40)
        ])
        
        let tapGesture = UITapGestureRecognizer(target: self, action: #selector(dismissKeyboard))
        view.addGestureRecognizer(tapGesture)
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
    
    @objc private func resetPasswordTapped() {
        guard let newPassword = newPasswordTextField.text, !newPassword.isEmpty,
              let confirmPassword = confirmPasswordTextField.text, !confirmPassword.isEmpty else {
            showAlert(title: "Error", message: "Please fill in all fields")
            return
        }
        
        guard newPassword == confirmPassword else {
            showAlert(title: "Error", message: "Passwords do not match")
            return
        }
        
        guard newPassword.count >= 8 else {
            showAlert(title: "Error", message: "Password must be at least 8 characters")
            return
        }
        
        performPasswordReset(newPassword: newPassword)
    }
    
    private func performPasswordReset(newPassword: String) {
        resetButton.isEnabled = false
        activityIndicator.startAnimating()
        
        PasswordResetService.shared.resetPassword(token: token, newPassword: newPassword) { [weak self] result in
            DispatchQueue.main.async {
                self?.resetButton.isEnabled = true
                self?.activityIndicator.stopAnimating()
                
                switch result {
                case .success:
                    self?.showSuccessAndDismiss()
                case .failure(let error):
                    self?.showAlert(title: "Error", message: error.localizedDescription)
                }
            }
        }
    }
    
    private func showSuccessAndDismiss() {
        let alert = UIAlertController(title: "Success", message: "Your password has been reset successfully", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { [weak self] _ in
            self?.navigationController?.popToRootViewController(animated: true)
        })
        present(alert, animated: true)
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

class PasswordResetService {
    static let shared = PasswordResetService()
    
    private init() {}
    
    func resetPassword(token: String, newPassword: String, completion: @escaping (Result<Void, Error>) -> Void) {
        DispatchQueue.global().asyncAfter(deadline: .now() + 2.0) {
            if token.isEmpty {
                completion(.failure(NSError(domain: "PasswordResetError", code: 401, userInfo: [NSLocalizedDescriptionKey: "Invalid token"])))
            } else {
                completion(.success(()))
            }
        }
    }
